import json
import os

class PersistentQueue:
    def __init__(self, storage_path):
        self.storage_path = storage_path
        self._initialize()

    def _initialize(self):
        if not os.path.exists(self.storage_path) or os.path.getsize(self.storage_path) == 0:
            # Initialize with an empty list/state if the file doesn't exist or is empty
            self.items = []

    def _load_data(self):
        try:
            with open(self.storage_path, 'r') as f:
                data = f.read()
                if data:
                    return json.loads(data)
                return None
        except FileNotFoundError:
            print("Storage file not found.")
            return []
        except json.JSONDecodeError:
            print("Could not decode JSON from storage file. Starting with empty queue.")
            return []

    def _save_data(self):
        # Simple implementation: save the current list of items
        try:
            with open(self.storage_path, 'w') as f:
                json.dump(self.items, f)
        except IOError as e:
            print(f"Error saving to storage: {e}")

    def put(self, item):
        """Adds an item to the back of the queue and persists it."""
        self.items.append(item)
        self._save_data()

    def get(self):
        """Removes and returns the item from the front of the queue, and persists state."""
        if not self.is_empty():
            item = self.items.pop(0)
            self._save_data()
            return item
        raise IndexError("Queue is empty")

    def peek(self):
        """Returns the item at the front without removing it."""
        if not self.is_empty():
            return self.items[0]
        raise IndexError("Queue is empty")

    def is_empty(self):
        """Checks if the queue is empty."""
        return len(self.items) == 0

